package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.APKConstant;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.APKConstantService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import lombok.Data;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedApkConstantService implements CachedService, APKConstantService {

    @Autowired
    private APKConstantService apkConstantService;

    private static final ThreadLocal<CachedApkConstantBuffer> BUFFER = new ThreadLocal<>();

    public CachedApkConstantService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public APKConstant getByKey(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Pensioenstelsel pensioenStelsel,
            LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedApkConstantService.getByKey");
        APKConstantKey key = new APKConstantKey(werkgeversCategorie, werknemersKengetal, pensioenStelsel);
        CachedApkConstantBuffer buffer = CachedApkConstantService.getBuffer();
        List<APKConstant> results = buffer.get(key);
        if (results == null) {
            results = apkConstantService.findByKey(werkgeversCategorie, werknemersKengetal, pensioenStelsel);
            buffer.put(key, results);
        }
        APKConstant result = zoekLijst(results, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }


    private APKConstant zoekLijst(List<APKConstant> lijst, LocalDate datum) {
        APKConstant result = null;
        for (APKConstant constant : lijst) {
            LocalDateInterval periode = new LocalDateInterval(constant.getBeginDatum(), constant.getEindDatum());
            if (periode.contains(datum)) {
                result = constant;
                break;
            }
        }
        return result;
    }

    @Override
    public void clearCache() {
        CachedApkConstantService.getBuffer().clear();
    }

    private static class CachedApkConstantBuffer {

        private final Map<APKConstantKey, List<APKConstant>> apkConstantBuffer = new HashMap<>();

        public List<APKConstant> get(APKConstantKey key) {
            return apkConstantBuffer.get(key);
        }

        public void put(APKConstantKey key, List<APKConstant> lijst) {
            apkConstantBuffer.put(key, lijst);
        }

        public void clear() {
            apkConstantBuffer.clear();
        }
    }

    private static CachedApkConstantBuffer getBuffer() {
        CachedApkConstantBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedApkConstantBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class APKConstantKey {

        private final int werkgeversCategorie;
        private final int werknemersKengetal;
        private final int pensioenStelsel;

        APKConstantKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Pensioenstelsel pensioenStelsel) {
            this.werkgeversCategorie = werkgeversCategorie.getCode();
            this.werknemersKengetal = werknemersKengetal.getCode();
            this.pensioenStelsel = pensioenStelsel.getCode();
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<APKConstant> findByKey(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Pensioenstelsel pensioenStelsel) {
        return apkConstantService.findByKey(werkgeversCategorie, werknemersKengetal, pensioenStelsel);
    }


    @Override
    public List<APKConstant> findAll() {
        return apkConstantService.findAll();
    }

    @Override
    public APKConstant create(APKConstant constant) {
        return apkConstantService.create(constant);
    }

    @Override
    public void update(APKConstant constant) {
        apkConstantService.update(constant);
    }

    @Override
    public void delete(APKConstant constant) {
        apkConstantService.delete(constant);
    }

    @Override
    public APKConstant getById(Integer id) {
        return apkConstantService.getById(id);
    }

    @Override
    public APKConstant getById(Integer id, String fetchFields) {
        return apkConstantService.getById(id, fetchFields);
    }

    @Override
    public APKConstant getByCriteria(CriteriaBuilder cb) {
        return apkConstantService.getByCriteria(cb);
    }


    @Override
    public List<APKConstant> findAll(String fetchFields) {
        return apkConstantService.findAll(fetchFields);
    }

    @Override
    public List<APKConstant> findByCriteria(CriteriaBuilder cb) {
        return apkConstantService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return apkConstantService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, APKConstant> cacheByCriteria(CriteriaBuilder cb) {
        return apkConstantService.cacheByCriteria(cb);
    }

    @Override
    public APKConstant getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return apkConstantService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<APKConstant> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return apkConstantService.findByCriteriaTemporalFree(cb);
    }
}
